# ---- Data loading ----

# Resolve data directory relative to this app.R file
APP_DIR <- if (interactive() && requireNamespace("rstudioapi", quietly = TRUE)) {
  dirname(rstudioapi::getSourceEditorContext()$path)
} else {
  tryCatch(dirname(sys.frame(1)$ofile), error = function(e) getwd())
}
DATA_DIR <- normalizePath(file.path(APP_DIR, "..", "adam", "data"), mustWork = FALSE)
if (!dir.exists(DATA_DIR)) {
  DATA_DIR <- normalizePath("outputs/cdiscpilot01/adam/data", mustWork = FALSE)
}
if (!dir.exists(DATA_DIR)) stop("Cannot find ADaM data directory. Set working directory to project root.")

data <- teal_data()
data <- within(data, {
  library(dplyr)

  DATA_DIR <- DATA_DIR_PLACEHOLDER

  read_adam <- function(name, data_dir) {
    csv_path <- file.path(data_dir, paste0(name, ".csv"))
    if (file.exists(csv_path)) {
      read.csv(csv_path, stringsAsFactors = FALSE)
    } else {
      stop(paste("Dataset", name, "not found in", data_dir))
    }
  }

  # --- Load datasets ---
  ADSL <- read_adam("adsl", DATA_DIR)
  ADAE <- read_adam("adae", DATA_DIR)
  ADLB <- read_adam("adlb", DATA_DIR)
  ADVS <- read_adam("advs", DATA_DIR)
  ADEX <- read_adam("adex", DATA_DIR)
  ADCM <- read_adam("adcm", DATA_DIR)
  ADQSADAS <- read_adam("adqsadas", DATA_DIR)
  ADQSCIBC <- read_adam("adqscibc", DATA_DIR)
  ADQSNPIX <- read_adam("adqsnpix", DATA_DIR)
  ADTTE <- read_adam("adtte", DATA_DIR)

  # --- Factor conversion (required by teal modules) ---

  factorize <- function(df, vars) {
    for (v in intersect(vars, names(df))) {
      df[[v]] <- factor(df[[v]])
    }
    df
  }

  common_factors <- c(
    "TRT01P", "TRT01A", "TRT01PN", "TRT01AN",
    "TRTP", "TRTA",
    "SEX", "RACE", "ETHNIC", "AGEGR1", "AGEGR1N",
    "SAFFL", "ITTFL", "EFFFL",
    "COMP8FL", "COMP16FL", "COMP24FL",
    "EOSSTT", "DCSREAS", "SITEGR1", "SITEID",
    "BMIBLGR1", "DURDSGR1", "DTHFL", "COUNTRY"
  )

  ae_factors <- c(
    "AEBODSYS", "AEDECOD", "AESEV", "AESER", "AEREL",
    "AEACN", "AEOUT", "TRTEMFL", "AOCCFL", "AOCCSFL", "AOCCPFL",
    "CQ01NAM"
  )

  bds_factors <- c(
    "PARAMCD", "PARAM", "AVISIT", "ABLFL", "ANL01FL",
    "ANRIND", "BNRIND", "SHIFT1"
  )

  tte_factors <- c("PARAMCD", "PARAM", "CNSR", "EVNTDESC", "CNSDTDSC")

  cm_factors <- c("CMDECOD", "CMCLAS", "CONCOMFL", "PREFL", "ONTRTFL")

  ADSL <- factorize(ADSL, common_factors)
  ADAE <- factorize(factorize(ADAE, common_factors), ae_factors)
  ADLB <- factorize(factorize(ADLB, common_factors), bds_factors)
  ADVS <- factorize(factorize(ADVS, common_factors), bds_factors)
  ADEX <- factorize(factorize(ADEX, common_factors), bds_factors)
  ADCM <- factorize(factorize(ADCM, common_factors), cm_factors)
  ADQSADAS <- factorize(factorize(ADQSADAS, common_factors), bds_factors)
  ADQSCIBC <- factorize(factorize(ADQSCIBC, common_factors), bds_factors)
  ADQSNPIX <- factorize(factorize(ADQSNPIX, common_factors), bds_factors)
  ADTTE <- factorize(factorize(ADTTE, common_factors), tte_factors)

  # Filter out Screen Failures for cleaner display
  ADSL <- ADSL %>% filter(ITTFL == "Y" | SAFFL == "Y")
}, DATA_DIR_PLACEHOLDER = DATA_DIR)

# Join keys
join_keys(data) <- default_cdisc_join_keys[
