join_keys(data)["ADQSADAS", "ADQSADAS"] <- c("STUDYID", "USUBJID", "PARAMCD", "AVISIT")
join_keys(data)["ADSL", "ADQSADAS"] <- c("STUDYID", "USUBJID")
join_keys(data)["ADQSCIBC", "ADQSCIBC"] <- c("STUDYID", "USUBJID", "PARAMCD", "AVISIT")
join_keys(data)["ADSL", "ADQSCIBC"] <- c("STUDYID", "USUBJID")
join_keys(data)["ADQSNPIX", "ADQSNPIX"] <- c("STUDYID", "USUBJID", "PARAMCD", "AVISIT")
join_keys(data)["ADSL", "ADQSNPIX"] <- c("STUDYID", "USUBJID")

